def L(lv,t,c,code='',tip=''):return(lv,t,c,code,tip)
JS=[
L(1,'What is JavaScript?','JavaScript is the programming language of the web. It runs directly in your browser and makes web pages interactive — responding to clicks, updating content dynamically, and communicating with servers. When you see console.log(), that is JavaScript\'s way of printing output.','// JavaScript prints with console.log\nconsole.log("Hello, World!");\n\n// You can do math\nconsole.log(5 + 3);  // 8\nconsole.log(typeof "hello"); // "string"','JavaScript is the only programming language that runs natively in all web browsers. console.log() is for developers — users do not see it.'),
L(1,'Variables and Constants','Variables store data values. Use let for values that change and const for values that stay the same. Variable names cannot start with a number and should be descriptive. Avoid var in modern code — it has confusing scoping behavior.','const name = "Alice";  // cannot change\nlet score = 0;         // can change\nscore = 10;            // OK\n// name = "Bob";       // Error!\n\n// Invalid names:\n// let 2ndPlace = true;  // Error!','Always use const by default. Only switch to let when you actually need to reassign. Never start a variable name with a number.'),
L(2,'Data Types','JavaScript has several built-in types: string (text in quotes), number (integers and decimals), boolean (true/false), null (intentionally empty), and undefined (not yet assigned). Use typeof to check a value\'s type.','let age = 25;            // number\nlet name = "Alice";      // string\nlet active = true;       // boolean\nlet empty = null;        // null\nlet x;                   // undefined\nconsole.log(typeof age); // "number"\nconsole.log(typeof "5"); // "string"','Unlike other languages, JavaScript has only one number type — no separate int or float. The number 3.14 and 42 are the same type.'),
L(2,'Strings and Template Literals','Strings are text wrapped in quotes. Template literals use backticks (`) and allow embedding variables with ${} syntax. Strings have useful methods like .length, .toUpperCase(), .includes(), and .slice().','const name = "Alice";\nconst greeting = `Hello, ${name}!`;\nconsole.log(greeting);         // "Hello, Alice!"\nconsole.log(name.length);      // 5\nconsole.log(name.toUpperCase()); // "ALICE"','Template literals with backticks are the modern way to build strings. The ${} syntax is called string interpolation.'),
L(3,'Type Conversion and Coercion','JavaScript often converts types automatically (coercion), which can cause surprising results. The + operator concatenates when one side is a string, but - always does math. Use Number() and String() for explicit conversion.','console.log("5" + 3);     // "53" (string!)\nconsole.log("5" - 3);     // 2 (number!)\nconsole.log(Number("42")); // 42\nconsole.log(String(100));  // "100"\nconsole.log(Boolean(0));   // false','The + operator is tricky: "5" + 3 gives "53" (concatenation), but "5" - 3 gives 2 (math). This catches many beginners.'),
L(3,'Comparison Operators','Always use === (strict equality) which checks both type AND value. Avoid == (loose equality) which does automatic type conversion and can lead to bugs. Other comparisons: !==, <, >, <=, >=.','console.log(5 === "5");   // false (strict)\nconsole.log(5 == "5");    // true (loose, avoid!)\nconsole.log(5 !== "5");   // true\nconsole.log(NaN === NaN); // false (!)','NaN is the only value not equal to itself. Use Number.isNaN() to check for it. Always prefer === over ==.'),
L(4,'Operators and Expressions','JavaScript has arithmetic (+, -, *, /, % remainder), assignment (=, +=, -=), and logical (&& AND, || OR, ! NOT) operators. The % operator gives the remainder of division, useful for checking even/odd numbers.','let x = 10;\nx += 5;    // 15\nx %= 4;    // 3 (remainder)\n\nconst isEven = x % 2 === 0;\nconst isAdult = age >= 18 && hasID;\nconst name = input || "Guest";','The ?? (nullish coalescing) operator only checks null/undefined, while || treats 0, "", and false as falsy too.'),
L(4,'Ternary and Short-Circuit','The ternary operator (?:) is a one-line if/else. Short-circuit evaluation uses && and || for quick conditionals. Optional chaining (?.) safely accesses properties that might not exist.','const status = age >= 18 ? "Adult" : "Minor";\n\n// short-circuit\nconst name = user && user.name;\nconst display = username || "Anonymous";\n\n// optional chaining\nconst city = user?.address?.city;','Optional chaining (?.) returns undefined instead of crashing when accessing properties of null/undefined.'),
L(5,'Arrays','Arrays hold ordered lists of items. They are zero-indexed (the first item is at index 0). You can store any type of data and check the count with .length. Use push() to add items to the end.','const fruits = ["apple", "banana", "cherry"];\nconsole.log(fruits[0]);     // "apple"\nconsole.log(fruits.length); // 3\nfruits.push("orange");\nconsole.log(fruits[fruits.length - 1]); // "orange"','Use const for arrays — you can still push/pop/modify contents. const only prevents reassigning the variable itself.'),
L(5,'Array Methods','Key array methods: push/pop (add/remove from end), shift/unshift (start), slice (copy a portion), splice (insert/remove), includes (check existence), indexOf (find position).','const nums = [1, 2, 3, 4, 5];\nnums.pop();                // removes 5\nnums.unshift(0);           // adds 0 at start\nconst mid = nums.slice(1, 3); // [1, 2]\nconsole.log(nums.includes(3)); // true','slice() returns a new array without modifying the original. splice() changes the original array in place.'),
L(6,'Functions','Functions are reusable code blocks. Define them with function keyword or as arrow functions (=>). Parameters can have default values. The return keyword sends a value back to the caller.','function add(a, b) {\n  return a + b;\n}\n\nconst multiply = (a, b) => a * b;\n\nfunction greet(name = "Guest") {\n  return `Hello, ${name}!`;\n}\nconsole.log(add(3, 4)); // 7','Arrow functions with a single expression can skip curly braces and the return keyword: (a, b) => a + b.'),
L(6,'Scope and Block Scoping','Variables declared with let and const are block-scoped — they only exist inside the {} block where they were declared. Functions also create their own scope. This prevents variable name conflicts.','if (true) {\n  let x = 10;\n  const y = 20;\n  // x and y only exist here\n}\n// x and y are NOT available here\n\nfunction demo() {\n  let local = "inside";\n}\n// local is NOT available here','Block scope is one reason let/const replaced var. var is function-scoped which causes many unintended bugs.'),
L(7,'Higher-Order Functions','Functions that take other functions as arguments are called higher-order functions. The three most important: map() transforms each item, filter() keeps items passing a test, forEach() runs code for each item.','const nums = [1, 2, 3, 4, 5];\n\nconst doubled = nums.map(n => n * 2);\n// [2, 4, 6, 8, 10]\n\nconst evens = nums.filter(n => n % 2 === 0);\n// [2, 4]','map() returns a new transformed array. filter() returns items that pass the test. Neither modifies the original array.'),
L(7,'Reduce','reduce() processes an entire array into a single value by running a function on each item with an accumulator. It is the most powerful array method but also the most complex.','const nums = [1, 2, 3, 4];\nconst sum = nums.reduce((acc, n) => acc + n, 0);\nconsole.log(sum); // 10\n\nconst max = nums.reduce((a, b) => a > b ? a : b);\nconsole.log(max); // 4','The second argument to reduce() is the initial value of the accumulator. Always provide it to avoid edge-case bugs.'),
L(8,'Objects','Objects store data as key-value pairs. Keys are strings (properties), values can be anything. Access properties with dot notation (obj.key) or bracket notation (obj["key"]).','const user = {\n  name: "Alice",\n  age: 25,\n  greet() {\n    return `Hi, I am ${this.name}`;\n  }\n};\nconsole.log(user.name);    // "Alice"\nconsole.log(user["age"]);  // 25','Use dot notation for known keys and bracket notation for dynamic keys stored in variables.'),
L(8,'Destructuring','Destructuring unpacks values from objects and arrays into their own variables in one line. You can set defaults and rename variables during destructuring.','const { name, age } = user;\nconst [first, second] = [10, 20];\n\n// with default\nconst { role = "user" } = user;\n\n// rename\nconst { name: userName } = user;','Destructuring works great in function parameters: function greet({ name, age }) { ... }'),
L(9,'Loops','JavaScript has several loop types: for (counter-based), for...of (iterate arrays), for...in (iterate object keys), and while (condition-based). Use break to exit early and continue to skip iterations.','for (let i = 0; i < 5; i++) {\n  console.log(i);  // 0, 1, 2, 3, 4\n}\n\nconst fruits = ["apple", "banana"];\nfor (const fruit of fruits) {\n  console.log(fruit);\n}','Use for...of for arrays and for...in for object keys. Mixing them up is a common mistake.'),
L(9,'Array Iteration Methods','Modern JavaScript prefers .forEach(), .map(), and .filter() over traditional for loops for cleaner, more readable code. forEach() is for side effects, map() is for transforming data.','const items = ["a", "b", "c"];\n\nitems.forEach((item, index) => {\n  console.log(`${index}: ${item}`);\n});\n\nconst upper = items.map(s => s.toUpperCase());\n// ["A", "B", "C"]','forEach() does not return anything. Use map() when you need a new transformed array.'),
L(10,'Closures','A closure is when an inner function remembers the variables from its outer function, even after the outer function has returned. This is how JavaScript creates private variables and data persistence.','function counter() {\n  let count = 0;\n  return function() {\n    count++;\n    return count;\n  };\n}\n\nconst inc = counter();\nconsole.log(inc()); // 1\nconsole.log(inc()); // 2','Closures power callbacks, event handlers, data privacy, and factory functions. They are a core JavaScript concept.'),
L(10,'Modules','Modern JavaScript uses import/export to share code between files. Each file is a module. export makes functions/variables available, import brings them in. IIFEs were the old way to create modules.','// math.js\nexport function add(a, b) {\n  return a + b;\n}\n\n// app.js\nimport { add } from "./math.js";\nconsole.log(add(2, 3)); // 5','ES modules (import/export) have replaced IIFEs and script tags for organizing JavaScript code.'),
L(11,'The DOM','The DOM (Document Object Model) represents HTML as a tree of objects that JavaScript can read and modify. Use getElementById, querySelector, and querySelectorAll to find elements.','const heading = document.getElementById("title");\nheading.textContent = "New Title";\n\nconst items = document.querySelectorAll(".item");\nitems.forEach(el => {\n  el.style.color = "blue";\n});','querySelector uses CSS selectors and returns the first match. querySelectorAll returns all matches as a NodeList.'),
L(11,'Creating and Modifying Elements','You can create new elements with createElement(), set their content and attributes, then add them to the page with appendChild() or insertBefore().','const li = document.createElement("li");\nli.textContent = "New Item";\nli.classList.add("highlight");\n\ndocument.getElementById("list")\n  .appendChild(li);','Use textContent (safe) over innerHTML (can be exploited with malicious HTML) when setting plain text content.'),
L(12,'Event Handling','Events let you respond to user actions. Use addEventListener() to attach handler functions. Common events: click, submit, keydown, input, mouseover, focus, blur, scroll, load.','const btn = document.getElementById("btn");\nbtn.addEventListener("click", (e) => {\n  console.log("Clicked!", e.target);\n});\n\n// To remove later:\n// btn.removeEventListener("click", handler);','e.target is the element that was actually clicked. e.currentTarget is the element the listener is attached to.'),
L(12,'Event Delegation','Instead of adding listeners to many child elements, add one listener to their parent. Events bubble up from child to parent, so the parent can handle them all.','document.getElementById("list")\n  .addEventListener("click", (e) => {\n    if (e.target.tagName === "LI") {\n      e.target.classList.toggle("done");\n    }\n  });','Event delegation is more efficient and automatically handles dynamically added elements.'),
L(13,'Async JavaScript','JavaScript is single-threaded but handles async tasks with callbacks, promises, and async/await. setTimeout runs code after a delay. The event loop manages the execution order.','console.log("Start");\nsetTimeout(() => {\n  console.log("After 2 seconds");\n}, 2000);\nconsole.log("End");\n// Output: Start, End, After 2 seconds','Code after setTimeout runs immediately — it does not wait. The callback runs later when the timer fires.'),
L(13,'Fetch API','fetch() makes HTTP requests and returns a Promise. The response must be parsed with .json() or .text(). Always handle errors with .catch() or try/catch.','fetch("https://api.example.com/data")\n  .then(response => response.json())\n  .then(data => console.log(data))\n  .catch(error => console.error(error));','Always handle errors with .catch() or try/catch. Network requests can fail due to downtime, CORS, or bad URLs.'),
L(14,'Promises','A Promise represents a future value. It can be in three states: pending (waiting), fulfilled (success with resolve), or rejected (failure with reject). Chain with .then() and .catch().','const loadData = new Promise((resolve, reject) => {\n  setTimeout(() => {\n    const success = true;\n    if (success) resolve("Data loaded");\n    else reject("Failed");\n  }, 1000);\n});\n\nloadData.then(console.log).catch(console.error);','Use Promise.all() to wait for multiple promises to finish, or Promise.race() for whichever finishes first.'),
L(14,'Async / Await','async/await is cleaner syntax for Promises. An async function always returns a Promise, and await pauses execution until a Promise resolves. Use try/catch for error handling.','async function fetchUser(id) {\n  try {\n    const res = await fetch(`/api/users/${id}`);\n    const user = await res.json();\n    return user;\n  } catch (err) {\n    console.error("Failed:", err);\n  }\n}','You can only use await inside an async function. Use try/catch for error handling instead of .catch().'),
L(15,'Spread and Rest Operators','The ... syntax has two uses: spread (expand arrays/objects) and rest (collect remaining items). Spread creates shallow copies, while rest gathers arguments into an array.','const a = [1, 2];\nconst b = [...a, 3, 4]; // [1,2,3,4]\n\nconst obj = { x: 1, y: 2 };\nconst copy = { ...obj, z: 3 };\n\nfunction sum(...nums) {\n  return nums.reduce((a, b) => a + b, 0);\n}','Spread creates shallow copies only. Nested objects/arrays still reference the originals — use structuredClone() for deep copies.'),
L(15,'Modern JavaScript Patterns','ES2020+ features: optional chaining (?.) for safe property access, nullish coalescing (??) for null/undefined defaults, computed property names, and array destructuring with rest.','const key = "name";\nconst obj = { [key]: "Alice" };\n\nconst city = user?.address?.city ?? "Unknown";\n\nconst [head, ...rest] = [1, 2, 3, 4];\n// head = 1, rest = [2, 3, 4]','These modern patterns make code shorter and safer. Use ?. instead of manually checking each level of nesting.'),
]
